```class Solution {
public:
    string solveEquation(string equation) {
        int leftX = 0, leftVal = 0, rightX = 0, rightVal = 0;
        bool left = true;
        int sign = 1, num = 0;
        for (char c : equation) {
            if (c == '=') {
                left = false;
                sign = 1;
                num = 0;
            } else if (c == '+' || c == '-') {
                if (num != 0) {
                    if (left) {
                        leftX += sign;
                        leftVal += num;
                    } else {
                        rightX += sign;
                        rightVal += num;
                    }
                    num = 0;
                }
                sign = (c == '+') ? 1 : -1;
            } else if (c == 'x') {
                if (num == 0) num = 1;
                if (left) leftX += sign * num;
                else rightX += sign * num;
                num = 0;
            } else {
                num = num * 10 + (c - '0');
            }
        }
        if (num != 0) {
            if (left) leftVal += sign * num;
            else rightVal += sign * num;
        }
        if (leftX == rightX) {
            if (leftVal == rightVal) return "Infinite solutions";
            else return "No solution";
        } else {
            int x = (rightVal - leftVal) / (leftX - rightX);
            return "x=" + to_string(x);
        }
    }
};
